const items = $input.all();
const normalized = [];

for (const item of items) {
  const data = item.json;

  let eventType = 'unknown';
  let chatId = null;
  let userId = null;
  let text = '';
  let callbackData = '';
  let callbackQueryId = '';
  let firstName = '';

  if (data.message) {
    eventType = 'message';
    chatId = data.message.chat?.id || null;
    userId = data.message.from?.id || null;
    text = data.message.text || '';
    firstName = data.message.from?.first_name || '';
  } else if (data.callback_query) {
    eventType = 'callback_query';
    chatId = data.callback_query.message?.chat?.id || null;
    userId = data.callback_query.from?.id || null;
    callbackData = data.callback_query.data || '';
    callbackQueryId = data.callback_query.id || '';
    firstName = data.callback_query.from?.first_name || '';
  }

  normalized.push({
    json: {
      eventType,
      chatId,
      userId,
      text,
      callbackData,
      callbackQueryId,
      firstName
    }
  });
}

return normalized;

const item = $input.first().json;
const text = item.text || '';

const urlRegex = /(https?:\/\/[^\s]+)/;
const match = text.match(urlRegex);
const url = match ? match[1] : '';

return [{
  json: {
    url,
    chatId: item.chatId,
    userId: item.userId,
    firstName: item.firstName
  }
}];

const input = $input.first();

if (!input || !input.json) {
  throw new Error('Clean HTML Content received no input item');
}

const data = input.json;

const url =
  data.url ||
  $('Extract URL').first().json.url;

let html =
  data.body ||
  data.data ||
  data.html ||
  data.response ||
  data.text ||
  '';

if (typeof html !== 'string') {
  html = JSON.stringify(html);
}

let title = '';
const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
if (titleMatch) {
  title = titleMatch[1];
}

let content = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
  .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
  .replace(/<header[\s\S]*?<\/header>/gi, ' ')
  .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();

title = title
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!content) {
  throw new Error('No readable content could be extracted from the fetched URL');
}

return [
  {
    json: {
      url,
      chatId: $('Extract URL').first().json.chatId,
      userId: $('Extract URL').first().json.userId,
      firstName: $('Extract URL').first().json.firstName,
      title: title || url,
      content: content.slice(0, 12000),
    },
  },
];

const items = $input.all();
const aiItem = items[0].json;

let rawOutput = aiItem.output || aiItem.text || aiItem.response || aiItem.result || aiItem.content || '';

if (typeof rawOutput === 'object') {
  rawOutput = JSON.stringify(rawOutput);
}

// Strip markdown code fences
rawOutput = rawOutput.replace(/^```json\s*/i, '').replace(/```\s*$/, '');

// Find first JSON object
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No JSON object found in AI output');
}

let parsed;
try {
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('Failed to parse JSON: ' + e.message);
}

// Validate and normalize
const title = parsed.title || 'Untitled';
const summary = parsed.summary || 'No summary available';
const keyPoints = Array.isArray(parsed.keyPoints) ? parsed.keyPoints : [];
const concepts = Array.isArray(parsed.concepts) ? parsed.concepts : [];
let difficulty = parsed.difficulty || 'intermediate';

if (!['beginner', 'intermediate', 'advanced'].includes(difficulty)) {
  difficulty = 'intermediate';
}

return [{
  json: {
    title,
    summary,
    keyPoints,
    concepts,
    difficulty
  }
}];

const input = $input.first();

if (!input || !input.json) {
  throw new Error('Prepare Material Data received no input item');
}

const teacher = input.json;
const cleaned = $('Clean HTML Content').first().json;

const now = new Date().toISOString();
const materialId = `LM-${Date.now()}`;

const keyPoints = Array.isArray(teacher.keyPoints) ? teacher.keyPoints : [];
const concepts = Array.isArray(teacher.concepts) ? teacher.concepts : [];

const keyPointsText = keyPoints.length
  ? keyPoints.map(point => `• ${point}`).join('\n')
  : 'No key points generated.';

const conceptsText = concepts.length
  ? concepts.map(concept => `• ${concept}`).join('\n')
  : 'No concepts generated.';

return [
  {
    json: {
      materialId,
      userId: cleaned.userId,
      chatId: cleaned.chatId,
      url: cleaned.url,
      title: teacher.title || cleaned.title || cleaned.url,
      content: cleaned.content,
      summary: teacher.summary,
      keyPointsJson: JSON.stringify(keyPoints),
      conceptsJson: JSON.stringify(concepts),
      keyPointsText,
      conceptsText,
      difficulty: teacher.difficulty || 'intermediate',
      addedAt: now,
    },
  },
];

