const materials = $input.all().map(item => item.json);

const original = $('Normalize Telegram Update').first().json;

if (!materials.length) {
  return [
    {
      json: {
        chatId: original.chatId,
        hasMaterials: false,
        text: 'No saved materials yet. Send /learn <url> first.',
      },
    },
  ];
}

const rows = materials.map(material => {
  const title = material.title || material.url || material.materialId;
  return [
    {
      text: title.slice(0, 64),
      callback_data: `topic:${material.materialId}`,
    },
  ];
});

return [
  {
    json: {
      chatId: original.chatId,
      hasMaterials: true,
      text: 'Choose a saved topic:',
      replyMarkup: {
        inline_keyboard: rows,
      },
    },
  },
];

const update = $('Normalize Telegram Update').first().json;

const callbackData = update.callbackData || '';

if (!callbackData.startsWith('topic:')) {
  throw new Error(`Expected topic callback data, got: ${callbackData}`);
}

return [
  {
    json: {
      materialId: callbackData.replace(/^topic:/, ''),
      userId: update.userId,
      chatId: update.chatId,
      callbackQueryId: update.callbackQueryId,
    },
  },
];

const item = $input.first();

if (!item || !item.json) {
  throw new Error('Parse Quiz JSON received no input item');
}

let raw =
  item.json.output ??
  item.json.text ??
  item.json.response ??
  item.json.result ??
  item.json.content ??
  item.json;

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const firstBrace = raw.indexOf('{');
const lastBrace = raw.lastIndexOf('}');

if (firstBrace === -1 || lastBrace === -1) {
  throw new Error(`Examiner output did not contain JSON: ${raw.slice(0, 500)}`);
}

const parsed = JSON.parse(raw.slice(firstBrace, lastBrace + 1));

if (!Array.isArray(parsed.questions)) {
  throw new Error('Examiner output missing questions array');
}

if (parsed.questions.length !== 5) {
  throw new Error(`Expected 5 questions, got ${parsed.questions.length}`);
}

const allowed = ['A', 'B', 'C', 'D'];

const questions = parsed.questions.map((question, index) => {
  if (!question.question) {
    throw new Error(`Question ${index + 1} missing question text`);
  }

  if (!Array.isArray(question.options) || question.options.length !== 4) {
    throw new Error(`Question ${index + 1} must have exactly 4 options`);
  }

  const options = allowed.map(key => {
    const found = question.options.find(option => option.key === key);
    if (!found || !found.text) {
      throw new Error(`Question ${index + 1} missing option ${key}`);
    }
    return { key, text: found.text };
  });

  if (!allowed.includes(question.correctAnswer)) {
    throw new Error(`Question ${index + 1} has invalid correctAnswer`);
  }

  return {
    id: question.id || `Q${index + 1}`,
    question: question.question,
    options,
    correctAnswer: question.correctAnswer,
    explanation: question.explanation || '',
  };
});

const material = $('Load Material').first().json;
const callback = $('Extract Material ID').first().json;

return [
  {
    json: {
      materialId: callback.materialId,
      userId: callback.userId,
      chatId: callback.chatId,
      title: material.title,
      questions,
    },
  },
];

const input = $input.first();

if (!input || !input.json) {
  throw new Error('Prepare Quiz Attempt received no input item');
}

const data = input.json;
const attemptId = `QA-${Date.now()}`;

return [
  {
    json: {
      attemptId,
      materialId: data.materialId,
      userId: data.userId,
      chatId: data.chatId,
      questionsJson: JSON.stringify(data.questions),
      answersJson: '[]',
      currentIndex: 0,
      status: 'in_progress',
      score: 0,
      questions: data.questions,
    },
  },
];

const attempt = $('Prepare Quiz Attempt').first().json;
const question = attempt.questions[0];

const optionLines = question.options
  .map(option => `${option.key}. ${option.text}`)
  .join('\n');

return [
  {
    json: {
      chatId: attempt.chatId,
      text: `Question 1 of 5:\n${question.question}\n\n${optionLines}`,
      replyMarkup: {
        inline_keyboard: [
          question.options.map(option => ({
            text: option.key,
            callback_data: `answer:${attempt.attemptId}:0:${option.key}`,
          })),
        ],
      },
    },
  },
];

const material = $input.first().json;
const callback = $('Extract Material ID').first().json;

const prompt = `You are the Examiner role in BrAIny Buddy, an AI learning assistant.

Create a five-question multiple-choice quiz from the provided learning material.
Return only raw valid JSON.
Do not use Markdown.
Do not wrap JSON in code fences.
Do not include commentary before or after the JSON.

Learning material:
Title: ${material.title}
Summary: ${material.summary}
Key points JSON: ${material.keyPointsJson}
Concepts JSON: ${material.conceptsJson}
Content:
${String(material.content || '').slice(0, 12000)}

Return exactly this JSON shape:
{
  "questions": [
    {
      "id": "Q1",
      "question": "string",
      "options": [
        {"key": "A", "text": "string"},
        {"key": "B", "text": "string"},
        {"key": "C", "text": "string"},
        {"key": "D", "text": "string"}
      ],
      "correctAnswer": "A",
      "explanation": "string"
    }
  ]
}

Rules:
- Generate exactly five questions.
- Questions must be specific to this material.
- Each question must have exactly four options: A, B, C, D.
- correctAnswer must be A, B, C, or D.
- explanation must help the learner understand the answer.`;

return [
  {
    json: {
      ...material,
      materialId: callback.materialId,
      userId: callback.userId,
      chatId: callback.chatId,
      callbackQueryId: callback.callbackQueryId,
      chatInput: prompt,
    },
  },
];

const update = $('Normalize Telegram Update').first().json;

const callbackData = update.callbackData || '';

if (!callbackData.startsWith('answer:')) {
  throw new Error(`Expected answer callback data, got: ${callbackData}`);
}

const parts = callbackData.split(':');

if (parts.length !== 4) {
  throw new Error(`Invalid answer callback format: ${callbackData}`);
}

const [, attemptId, questionIndexRaw, selectedOption] = parts;
const questionIndex = Number(questionIndexRaw);

if (!Number.isInteger(questionIndex)) {
  throw new Error(`Invalid question index: ${questionIndexRaw}`);
}

if (!['A', 'B', 'C', 'D'].includes(selectedOption)) {
  throw new Error(`Invalid selected option: ${selectedOption}`);
}

return [
  {
    json: {
      attemptId,
      questionIndex,
      selectedOption,
      userId: update.userId,
      chatId: update.chatId,
      callbackQueryId: update.callbackQueryId,
      answeredAt: new Date().toISOString(),
    },
  },
];

const answer = $('Parse Answer Callback').first().json;
const attempt = $input.first().json;

const questions = JSON.parse(attempt.questionsJson || '[]');
let answers = JSON.parse(attempt.answersJson || '[]');

if (!questions.length) {
  throw new Error('Quiz attempt has no questions');
}

const question = questions[answer.questionIndex];

if (!question) {
  throw new Error(`Question index not found: ${answer.questionIndex}`);
}

answers = answers.filter(existing => existing.questionIndex !== answer.questionIndex);
answers.push({
  questionIndex: answer.questionIndex,
  selectedOption: answer.selectedOption,
  answeredAt: answer.answeredAt,
});
answers.sort((a, b) => a.questionIndex - b.questionIndex);

const isComplete = answers.length >= questions.length;
const nextIndex = answer.questionIndex + 1;

if (isComplete) {
  const correctCount = answers.reduce((count, item) => {
    const q = questions[item.questionIndex];
    return count + (q && item.selectedOption === q.correctAnswer ? 1 : 0);
  }, 0);

  const score = Math.round((correctCount / questions.length) * 100);

  const feedback = questions.map((q, index) => {
    const item = answers.find(a => a.questionIndex === index);
    const selected = item ? item.selectedOption : 'No answer';
    const isCorrect = selected === q.correctAnswer;

    let line = `${index + 1}. ${isCorrect ? 'Correct' : 'Incorrect'} — selected ${selected}, correct ${q.correctAnswer}`;

    if (!isCorrect && q.explanation) {
      line += `\nExplanation: ${q.explanation}`;
    }

    return line;
  }).join('\n\n');

  return [
    {
      json: {
        attemptId: answer.attemptId,
        userId: answer.userId,
        chatId: answer.chatId,
        answersJson: JSON.stringify(answers),
        currentIndex: questions.length,
        status: 'completed',
        score,
        isComplete: true,
        text: `Quiz complete!\n\nScore: ${score}% (${correctCount}/${questions.length})\n\n${feedback}`,
      },
    },
  ];
}

const nextQuestion = questions[nextIndex];
const optionLines = nextQuestion.options
  .map(option => `${option.key}. ${option.text}`)
  .join('\n');

const callbacks = Object.fromEntries(
  nextQuestion.options.map(option => [
    option.key,
    `answer:${answer.attemptId}:${nextIndex}:${option.key}`,
  ])
);

return [
  {
    json: {
      attemptId: answer.attemptId,
      userId: answer.userId,
      chatId: answer.chatId,
      answersJson: JSON.stringify(answers),
      currentIndex: nextIndex,
      status: 'in_progress',
      score: 0,
      isComplete: false,
      text: `Question ${nextIndex + 1} of ${questions.length}:\n${nextQuestion.question}\n\n${optionLines}`,

      buttonAText: 'A',
      buttonACallback: callbacks.A,
      buttonBText: 'B',
      buttonBCallback: callbacks.B,
      buttonCText: 'C',
      buttonCCallback: callbacks.C,
      buttonDText: 'D',
      buttonDCallback: callbacks.D,
    },
  },
];
